lines = []

# ─── DASHBOARD HOME ──────────────────────────────────────────────────────────
lines.append('')
lines.append('// ─── DASHBOARD HOME ──────────────────────────────────────────────────────────')
lines.append('function DashboardHome({ instruments, documents, training, equipment, suppliers, nonConformances, auditPlans, envRecords, setActiveTab }) {')
lines.append('  const now = new Date(); now.setHours(0,0,0,0);')
lines.append('  const overdueInst = instruments.filter(i => daysUntil(i.nextCalibration) < 0).length;')
lines.append('  const upcomingInst = instruments.filter(i => { const d=daysUntil(i.nextCalibration); return d>=0&&d<=30; }).length;')
lines.append('  const overdueDoc = documents.filter(d => daysUntil(d.nextReview) < 0).length;')
lines.append('  const expiredTrain = training.filter(t => daysUntil(t.validUntil) < 0).length;')
lines.append('  const overdueEquip = equipment.filter(e => daysUntil(e.nextMaintenance) < 0).length;')
lines.append('  const openNc = nonConformances.filter(n => n.status !== "\u5df2\u95dc\u9589").length;')
lines.append('  const overdueNc = nonConformances.filter(n => n.status !== "\u5df2\u95dc\u9589" && daysUntil(n.dueDate) < 0).length;')
lines.append('  const upcomingAudit = auditPlans.filter(a => a.status === "\u8a08\u756b\u4e2d" && daysUntil(a.scheduledDate) >= 0 && daysUntil(a.scheduledDate) <= 30).length;')
lines.append('  const envPassRate = envRecords.length > 0 ? Math.round(envRecords.filter(r => r.result === "\u5408\u683c").length / envRecords.length * 100) : 0;')
lines.append('  const poorSupplier = suppliers.filter(s => s.score < 70).length;')
lines.append('  const alerts = [];')
lines.append('  if (overdueInst > 0) alerts.push({ type: "error", msg: `\u6709 ${overdueInst} \u4e2a\u5c0f\u5668\u6821\u6b63\u9047\u671f\uff0c\u8acb\u7acb\u5373\u5b89\u6392\u8a66\u9a57` });')
lines.append('  if (upcomingInst > 0) alerts.push({ type: "warn", msg: `\u6709 ${upcomingInst} \u4e2a\u5c0f\u5668\u5c07\u65bc 30 \u5929\u5167\u5230\u671f\u6821\u6b63` });')
lines.append('  if (overdueDoc > 0) alerts.push({ type: "error", msg: `\u6709 ${overdueDoc} \u4efd\u6587\u4ef6\u9846\u958b\u8907\u5be9\u9047\u671f` });')
lines.append('  if (expiredTrain > 0) alerts.push({ type: "error", msg: `\u6709 ${expiredTrain} \u6a94\u54e1\u8a13\u7df4\u8a8d\u8b49\u5df2\u904e\u671f` });')
lines.append('  if (overdueEquip > 0) alerts.push({ type: "error", msg: `\u6709 ${overdueEquip} \u53f0\u8a2d\u5099\u4fdd\u990a\u9047\u671f` });')
lines.append('  if (overdueNc > 0) alerts.push({ type: "error", msg: `\u6709 ${overdueNc} \u4e2a\u4e0d\u7b26\u5408\u9805\u76ee\u5df2\u903e\u671f\u672a\u95dc\u9589` });')
lines.append('  if (upcomingAudit > 0) alerts.push({ type: "warn", msg: `${upcomingAudit} \u5834\u5167\u90e8\u7a3d\u6838\u5c07\u65bc 30 \u5929\u5167\u57f7\u884c` });')
lines.append('  if (poorSupplier > 0) alerts.push({ type: "warn", msg: `\u6709 ${poorSupplier} \u5bb6\u4f9b\u61c9\u5546\u8a55\u5206\u4e0d\u8db3 70 \u5206` });')
lines.append('  if (envPassRate < 90) alerts.push({ type: "warn", msg: `\u6f54\u6de8\u5ba4\u74b0\u5883\u5408\u683c\u7387\u50c5 ${envPassRate}%` });')
lines.append('  const kpis = [')
lines.append('    { label: "\u6821\u6b63\u5c0f\u5668", value: instruments.length, sub: overdueInst > 0 ? `${overdueInst}\u4e2a\u9047\u671f` : "\u5168\u90e8\u6b63\u5e38", color: overdueInst > 0 ? "#ef4444" : "#60a5fa", tab: "calibration" },')
lines.append('    { label: "\u7a0b\u5e8f\u6587\u4ef6", value: documents.length, sub: overdueDoc > 0 ? `${overdueDoc}\u4efd\u9e1e\u671f` : "\u5168\u90e8\u6709\u6548", color: overdueDoc > 0 ? "#ef4444" : "#22c55e", tab: "documents" },')
lines.append('    { label: "\u8a13\u7df4\u8a18\u9304", value: training.length, sub: expiredTrain > 0 ? `${expiredTrain}\u4eba\u904e\u671f` : "\u5168\u90e8\u6709\u6548", color: expiredTrain > 0 ? "#ef4444" : "#22c55e", tab: "training" },')
lines.append('    { label: "\u8a2d\u5099\u4fdd\u990a", value: equipment.length, sub: overdueEquip > 0 ? `${overdueEquip}\u53f0\u9e1e\u671f` : "\u5168\u90e8\u6b63\u5e38", color: overdueEquip > 0 ? "#ef4444" : "#22c55e", tab: "equipment" },')
lines.append('    { label: "\u4f9b\u61c9\u5546", value: suppliers.length, sub: poorSupplier > 0 ? `${poorSupplier}\u5bb6\u8a55\u5206\u4e0d\u8db3` : "\u5168\u90e8\u5408\u683c", color: poorSupplier > 0 ? "#eab308" : "#22c55e", tab: "supplier" },')
lines.append('    { label: "\u4e0d\u7b26\u5408\u9805", value: nonConformances.length, sub: openNc > 0 ? `${openNc}\u4e2a\u672a\u95dc\u9589` : "\u5168\u90e8\u5df2\u95dc\u9589", color: openNc > 0 ? "#ef4444" : "#22c55e", tab: "nonconformance" },')
lines.append('    { label: "\u7a3d\u6838\u8a08\u756b", value: auditPlans.length, sub: upcomingAudit > 0 ? `${upcomingAudit}\u573030\u5929\u5167\u57f7\u884c` : "\u5982\u671f\u9032\u884c", color: upcomingAudit > 0 ? "#f97316" : "#8b5cf6", tab: "auditplan" },')
lines.append('    { label: "\u74b0\u5883\u76e3\u6e2c", value: envRecords.length, sub: `\u5408\u683c\u7387 ${envPassRate}%`, color: envPassRate >= 90 ? "#14b8a6" : envPassRate >= 80 ? "#eab308" : "#ef4444", tab: "environment" },')
lines.append('  ];')
lines.append('  return (')
lines.append('    <div>')
lines.append('      <div style={{ marginBottom: 28 }}>')
lines.append('        <div style={{ fontSize: 22, fontWeight: 800, color: "#e2e8f0", letterSpacing: 1 }}>\u6f54\u6de8\u4f01\u696d\u6709\u9650\u516c\u53f8 ISO 9001:2015</div>')
lines.append('        <div style={{ fontSize: 14, color: "#64748b", marginTop: 4 }}>\u54c1\u8cea\u7ba1\u7406\u7cfb\u7d71\u81ea\u52d5\u7a3d\u6838\u4e3b\u63a7\u53f0 \u2014 {new Date().toLocaleDateString("zh-TW", { year:"numeric", month:"long", day:"numeric" })}</div>')
lines.append('      </div>')
lines.append('      {alerts.length > 0 && (')
lines.append('        <div style={{ marginBottom: 24 }}>')
lines.append('          <div style={{ fontSize: 13, color: "#94a3b8", fontWeight: 700, marginBottom: 10 }}>\u26a0 \u7cfb\u7d71\u8b66\u793a ({alerts.length})</div>')
lines.append('          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>')
lines.append('            {alerts.map((a, i) => (')
lines.append('              <div key={i} style={{ background: a.type==="error"?"rgba(239,68,68,0.08)":"rgba(234,179,8,0.08)", border: `1px solid ${a.type==="error"?"rgba(239,68,68,0.3)":"rgba(234,179,8,0.3)"}`, borderRadius: 10, padding: "10px 16px", fontSize: 13, color: a.type==="error"?"#fca5a5":"#fde68a", display:"flex", alignItems:"center", gap:8 }}>')
lines.append('                <span>{a.type==="error"?"\u274c":"\u26a0\ufe0f"}</span><span>{a.msg}</span>')
lines.append('              </div>')
lines.append('            ))}')
lines.append('          </div>')
lines.append('        </div>')
lines.append('      )}')
lines.append('      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(180px, 1fr))", gap: 14, marginBottom: 28 }}>')
lines.append('        {kpis.map(k => (')
lines.append('          <div key={k.tab} onClick={() => setActiveTab(k.tab)} style={{ background: "rgba(255,255,255,0.04)", border: `1px solid ${k.color}40`, borderRadius: 14, padding: "18px 20px", cursor: "pointer", transition: "all 0.2s" }}')
lines.append('            onMouseEnter={e => e.currentTarget.style.background="rgba(255,255,255,0.08)"}')
lines.append('            onMouseLeave={e => e.currentTarget.style.background="rgba(255,255,255,0.04)"} >')
lines.append('            <div style={{ fontSize: 28, fontWeight: 800, color: k.color, lineHeight: 1 }}>{k.value}</div>')
lines.append('            <div style={{ fontSize: 13, color: "#94a3b8", marginTop: 6 }}>{k.label}</div>')
lines.append('            <div style={{ fontSize: 11, color: k.color, marginTop: 4, fontWeight: 600 }}>{k.sub}</div>')
lines.append('          </div>')
lines.append('        ))}')
lines.append('      </div>')
lines.append('      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>')
lines.append('        <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 14, padding: 20 }}>')
lines.append('          <div style={{ fontSize: 14, fontWeight: 700, color: "#e2e8f0", marginBottom: 14 }}>\u6700\u8fd1\u6821\u6b63\u5230\u671f\u5c0f\u5668</div>')
lines.append('          {[...instruments].sort((a,b) => daysUntil(a.nextCalibration)-daysUntil(b.nextCalibration)).slice(0,5).map(inst => (')
lines.append('            <div key={inst.id} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 0", borderBottom:"1px solid rgba(255,255,255,0.05)" }}>')
lines.append('              <div>')
lines.append('                <div style={{ fontSize:13, color:"#e2e8f0" }}>{inst.name}</div>')
lines.append('                <div style={{ fontSize:11, color:"#64748b" }}>{inst.id}</div>')
lines.append('              </div>')
lines.append('              <Badge color={urgencyColor(daysUntil(inst.nextCalibration))}>{urgencyLabel(daysUntil(inst.nextCalibration))}</Badge>')
lines.append('            </div>')
lines.append('          ))}')
lines.append('        </div>')
lines.append('        <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 14, padding: 20 }}>')
lines.append('          <div style={{ fontSize: 14, fontWeight: 700, color: "#e2e8f0", marginBottom: 14 }}>\u672a\u95dc\u9589\u4e0d\u7b26\u5408\u9805\u76ee</div>')
lines.append('          {nonConformances.filter(n => n.status !== "\u5df2\u95dc\u9589").slice(0,5).map(nc => (')
lines.append('            <div key={nc.id} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 0", borderBottom:"1px solid rgba(255,255,255,0.05)" }}>')
lines.append('              <div>')
lines.append('                <div style={{ fontSize:12, color:"#e2e8f0" }}>{nc.description.slice(0,20)}{nc.description.length>20?"...":""}</div>')
lines.append('                <div style={{ fontSize:11, color:"#64748b" }}>{nc.id} \u2014 {nc.dept}</div>')
lines.append('              </div>')
lines.append('              <Badge color={daysUntil(nc.dueDate)<0?"#ef4444":daysUntil(nc.dueDate)<=7?"#eab308":"#60a5fa"}>{daysUntil(nc.dueDate)<0?"\u9060\u671f":"\u5265"+daysUntil(nc.dueDate)+"\u5929"}</Badge>')
lines.append('            </div>')
lines.append('          ))}')
lines.append('          {nonConformances.filter(n=>n.status!=="\u5df2\u95dc\u9589").length===0 && <div style={{color:"#22c55e",fontSize:13,marginTop:8}}>\u2713 \u76ee\u524d\u6c92\u6709\u672a\u95dc\u9589\u4e0d\u7b26\u5408\u9805</div>}')
lines.append('        </div>')
lines.append('      </div>')
lines.append('    </div>')
lines.append('  );')
lines.append('}')

content = '\n'.join(lines) + '\n'
with open(r'C:\Users\USER\Desktop\自動稽核程式\audit-dashboard.jsx', 'a', encoding='utf-8-sig') as f:
    f.write(content)
print('Part9 DashboardHome OK')
